$students=$db->query('SELECT id,full_name FROM students')->fetchAll();$courses=$db->query('SELECT id,title FROM courses')->fetchAll();$rows=$db->query('SELECT c.*,s.full_name,co.title FROM certificates c JOIN students s ON s.id=c.student_id JOIN courses co ON co.id=c.course_id ORDER BY c.id DESC')->fetchAll();?><h2>Certificates</h2><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><select name="student_id"><?php foreach($students as $s):?><option value="<?=$s['id']?>"><?=e($s['full_name'])?></option><?php endforeach;?></select><select name="course_id"><?php foreach($courses as $c):?><option value="<?=$c['id']?>"><?=e($c['title'])?></option><?php endforeach;?></select><input name="verification_id" placeholder="Auto if blank"><input type="date" name="issue_date"><input type="file" name="certificate_file" required><button>Issue</button></form><table border="1"><tr><th>ID</th><th>Student</th><th>Course</th><th>Date</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['verification_id'])?></td><td><?=e($r['full_name'])?></td><td><?=e($r['title'])?></td><td><?=e($r['issue_date'])?></td></tr><?php endforeach;?></table>
